// Sync shared <nav> + <footer> partials onto every static HTML page that
// isn't generated by gen-landing-pages.mjs — impressum / datenschutz / agb.
//
// For each partial:
//   - Finds the block bounded by begin/end markers in the file and replaces
//     with the shared version from _nav.mjs / _footer.mjs.
//   - On first run (no markers), seeds markers by locating the existing
//     legacy block via a fallback regex, then wraps-and-replaces.
// Also:
//   - Rewrites overflow-x:hidden → overflow-x:clip on html/body so sticky
//     positioning on the nav actually works (hidden creates a scroll
//     container and breaks sticky on every supported browser).
//   - Ensures nav.js is loaded before </body> (hamburger + dropdown).
//
// Run: node scripts/sync-legal-nav.mjs
import fs from 'node:fs';
import path from 'node:path';
import { NAV_STYLE, NAV_HTML } from './_nav.mjs';
import { FOOTER_STYLE, FOOTER_HTML } from './_footer.mjs';

const LEGAL_PAGES = [
  'apps/web/public/impressum/index.html',
  'apps/web/public/datenschutz/index.html',
  'apps/web/public/agb/index.html',
  'apps/web/public/avv/index.html',
  'apps/web/public/sub-processors/index.html',
];

// Marker regexes.
const NAV_CSS_RE     = /\/\*--nav-css-begin--\*\/[\s\S]*?\/\*--nav-css-end--\*\//;
const NAV_HTML_RE    = /<!--nav-html-begin-->[\s\S]*?<!--nav-html-end-->/;
const FOOTER_CSS_RE  = /\/\*--footer-css-begin--\*\/[\s\S]*?\/\*--footer-css-end--\*\//;
const FOOTER_HTML_RE = /<!--footer-html-begin-->[\s\S]*?<!--footer-html-end-->/;

// First-run seeding patterns. Each matches the legacy unmarked block
// shipped before the partial system existed, so we can wrap it in markers
// on a single migration pass.
const NAV_CSS_SEED_RE     = /\.ph-header\{[\s\S]*?@media\(min-width:768px\)\{\.ph-login\{display:block\}\}/;
const NAV_HTML_SEED_RE    = /<header class="ph-header">[\s\S]*?<\/header>/;
// Existing legal footer starts at `/* ── Site footer` and runs until
// the last footer-bottom rule. A cleaner seed pattern: match the
// `.site-footer{` selector through the closing }. We pick a fixed
// terminator that appears in every legal page.
const FOOTER_CSS_SEED_RE  = /\.site-footer\{[\s\S]*?\.footer-bottom a:hover\{color:rgba\(255,255,255,\.8\)[^}]*\}/;
const FOOTER_HTML_SEED_RE = /<footer class="site-footer">[\s\S]*?<\/footer>/;

function applyBlock(src, markedRe, seedRe, replacement, label, file) {
  if (markedRe.test(src)) return src.replace(markedRe, replacement);
  if (seedRe.test(src))  {
    console.log(`  ↪ seeded ${label} markers in ${file}`);
    return src.replace(seedRe, replacement);
  }
  console.warn(`! couldn't locate ${label} block in ${file}`);
  return null;
}

let failures = 0;

for (const rel of LEGAL_PAGES) {
  const file = path.resolve(rel);
  if (!fs.existsSync(file)) {
    console.error(`✗ missing: ${rel}`);
    failures++;
    continue;
  }
  let src = fs.readFileSync(file, 'utf8');
  const original = src;

  // 1. Nav CSS + HTML.
  const stepA = applyBlock(src, NAV_CSS_RE, NAV_CSS_SEED_RE, NAV_STYLE, 'nav CSS', rel);
  if (stepA === null) { failures++; continue; }
  const stepB = applyBlock(stepA, NAV_HTML_RE, NAV_HTML_SEED_RE, NAV_HTML, 'nav HTML', rel);
  if (stepB === null) { failures++; continue; }
  src = stepB;

  // 2. Footer CSS + HTML.
  const stepC = applyBlock(src, FOOTER_CSS_RE, FOOTER_CSS_SEED_RE, FOOTER_STYLE, 'footer CSS', rel);
  if (stepC === null) { failures++; continue; }
  const stepD = applyBlock(stepC, FOOTER_HTML_RE, FOOTER_HTML_SEED_RE, FOOTER_HTML, 'footer HTML', rel);
  if (stepD === null) { failures++; continue; }
  src = stepD;

  // 3. Sticky-fix: overflow-x:hidden on html/body prevents position:sticky
  //    from pinning to the viewport — it pins to the scrollable ancestor
  //    (the body itself) which never moves. clip keeps the horizontal
  //    overflow suppression without creating that ancestor scroll context.
  src = src.replace(/(html|body|#root)\{([^}]*?)overflow-x:hidden/g, '$1{$2overflow-x:clip');
  // Some pages put the property on multiple lines; normalise both shapes.
  src = src.replace(/overflow-x:hidden(?=[;}])/g, 'overflow-x:clip');

  // 4. nav.js script tag.
  if (!src.includes('/nav.js')) {
    src = src.replace('</body>', '<script src="/nav.js" defer></script>\n</body>');
  }

  if (src !== original) {
    fs.writeFileSync(file, src);
    console.log(`✓ ${rel}`);
  } else {
    console.log(`· ${rel} (no change)`);
  }
}

if (failures > 0) {
  process.exit(1);
}
